def skip(self, type):
    if type == TType.BOOL:
        if not self.trans.readBool():
            raise TProtocolException(TProtocolException.INVALID_DATA, "Invalid boolean value")
    elif type == TType.BYTE:
        if not self.trans.readByte():
            raise TProtocolException(TProtocolException.INVALID_DATA, "Invalid byte value")
    elif type == TType.I16:
        if not self.trans.readI16():
            raise TProtocolException(TProtocolException.INVALID_DATA, "Invalid 16-bit integer value")
    elif type == TType.I32:
        if not self.trans.readI32():
            raise TProtocolException(TProtocolException.INVALID_DATA, "Invalid 32-bit integer value")
    elif type == TType.I64:
        if not self.trans.readI64():
            raise TProtocolException(TProtocolException.INVALID_DATA, "Invalid 64-bit integer value")
    elif type == TType.DOUBLE:
        if not self.trans.readDouble():
            raise TProtocolException(TProtocolException.INVALID_DATA, "Invalid double value")
    elif type == TType.FLOAT:
        if not self.trans.readFloat():
            raise TProtocolException(TProtocolException.INVALID_DATA, "Invalid float value")
    elif type == TType.STRING:
        if not self.trans.readString():
            raise TProtocolException(TProtocolException.INVALID_DATA, "Invalid string value")
    elif type == TType.STRUCT:
        name = self.readStructBegin()
        while True:
            (name, type, id) = self.readFieldBegin()
            if type == TType.STOP:
                break
            self.skip(type)
            self.readFieldEnd()
        self.readStructEnd()
    elif type == TType.MAP:
        (ktype, vtype, size) = self.readMapBegin()
        for _ in range(size):
            self.skip(ktype)
            self.skip(vtype)
        self.readMapEnd()
    elif type == TType.SET:
        (etype, size) = self.readSetBegin()
        for _ in range(size):
            self.skip(etype)
        self.readSetEnd()
    elif type == TType.LIST:
        (etype, size) = self.readListBegin()
        for _ in range(size):
            self.skip(etype)
        self.readListEnd()
    else:
        raise TProtocolException(TProtocolException.INVALID_DATA, "Unexpected type for skipping {}".format(type))
```

