    def from_login(email: str, password: str) -> AuthType:
        if not isinstance(email, str) or not isinstance(password, str):
            raise ValueError("Email and password must be strings")
        cl = AuthClient()
        auth_data = cl.login(email, password)
        return APIKeyAuth(auth_data['api_key'])

    def store(self, filename: str) -> None:
        if not isinstance(filename, str):
            raise ValueError("Filename must be a string")
        filename = pathlib.Path(filename)
        secret_file = _SecretFile(filename)
        secret_file.write(self.to_dict())

class _SecretFile:
    def __init__(self, path: pathlib.Path) -> None:
        self.path = path
        self.permissions = stat.S_IRUSR | stat.S_IWUSR

    def write(self, contents: dict) -> None:
        try:
            with self.path.open('w') as fp:
                json.dump(contents, fp)
        except (FileNotFoundError, KeyError, json.JSONDecodeError):
            raise ValueError("Invalid JSON format")

    def read(self) -> dict:
        try:
            with self.path.open('r') as fp:
                return json.load(fp)
        except FileNotFoundError:
            return {}
        except KeyError:
            return {}
        except json.JSONDecodeError:
            return {}

class APIKeyAuth(httpx.BasicAuth, Auth):
    # ...

