    def from_dict(data: dict) -> APIKeyAuth:
        if not isinstance(data, dict):
            raise ValueError("Data must be a dictionary")
        api_key = data.get('key')
        if not api_key:
            raise ValueError("API key not found")
        return self(api_key)

    def to_dict(self) -> dict:
